oxy_webhelp_navlinks = {"aws_workloads-d30753e12591":{"topics":[{"title":"Introduction to AWS protection","shortdesc":"<p class=\"shortdesc\">Describes the key features, common protection terms, high-level\n                    architecture, and tag management for protecting AWS workloads with <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/aws_key_features_protection.html","menu":{"hasChildren":false},"tocID":"tocId-d30753e12607","next":"tocId-d30753e12607"},{"title":"AWS protection implementation workflow","shortdesc":"<p class=\"shortdesc\">The AWS protection implementation workflow involves a structured approach to secure         data management, starting with planning and preparation, followed by cloud account setup,         infrastructure configuration, workload protection, continuous management and optimization,         and workload recovery.<\/p>","href":"saas\/aws_protect_implementation.html","attributes":{"data-id":"aws_protect_implementation"},"menu":{"hasChildren":false},"tocID":"aws_protect_implementation-d30753e12763","topics":[]},{"title":"Quick links for AWS workloads","shortdesc":"<p class=\"shortdesc\">Immediate access to important tasks and information, enabling quick setup, daily         operations, and critical recovery.<\/p>","href":"saas\/aws_quick_links.html","attributes":{"data-id":"aws_quick_links"},"menu":{"hasChildren":false},"tocID":"aws_quick_links-d30753e12774","topics":[]},{"title":"Plan your AWS protection","shortdesc":"<p class=\"shortdesc\">Before setting up an AWS cloud account in <span class=\"ph\">RSC<\/span>, it is necessary to         plan the user and access management for designated <span class=\"ph\">RSC<\/span> users. This planning         also involves reviewing the permissions that <span class=\"ph\">RSC<\/span> requires in your AWS         environment to protect your AWS workloads.<\/p>","href":"saas\/aws_planning_protection.html","attributes":{"data-id":"aws_planning_protection"},"menu":{"hasChildren":false},"tocID":"aws_planning_protection-d30753e12785","next":"aws_planning_protection-d30753e12785"},{"title":"Set up AWS cloud accounts","shortdesc":"<p class=\"shortdesc\">You can set up an AWS cloud account in <span class=\"ph\">RSC<\/span> and start protecting your         AWS workloads.<\/p>","href":"saas\/aws_cloud_acc_setup.html","attributes":{"data-id":"aws_cloud_acc_setup"},"menu":{"hasChildren":false},"tocID":"aws_cloud_acc_setup-d30753e13005","next":"aws_cloud_acc_setup-d30753e13005"},{"title":"Set up Exocompute on AWS","shortdesc":"<p class=\"shortdesc\">With the Exocompute on AWS feature, <span class=\"ph\">RSC<\/span> launches an Elastic         Kubernetes Service cluster to perform various operations to protect AWS workloads. <span class=\"ph\">RSC<\/span> uses the Elastic Kubernetes Service cluster as a compute resource in         your AWS account.<\/p>","href":"saas\/exocompute_for_aws.html","attributes":{"data-id":"exocompute_for_aws"},"menu":{"hasChildren":false},"tocID":"exocompute_for_aws-d30753e13746","next":"exocompute_for_aws-d30753e13746"},{"title":"Set up AWS storage tiering","shortdesc":"<p class=\"shortdesc\">You can use AWS storage tiering to archive Amazon EC2 instance<span class=\"ph\">, EBS volume, or DynamoDB table<\/span> snapshots         that exceed a specified threshold to Amazon S3 storage classes. By archiving snapshots to         these storage classes, you can optimize costs.<\/p>","href":"saas\/aws_storage_tiering_setup.html","attributes":{"data-id":"aws_storage_tiering_setup"},"menu":{"hasChildren":false},"tocID":"aws_storage_tiering_setup-d30753e14327","next":"aws_storage_tiering_setup-d30753e14327"},{"title":"Set up AWS workloads protection","shortdesc":"<p class=\"shortdesc\">You can set up SLA Domains to apply data protection policies, ensuring automatic and         hierarchical protection of AWS accounts and individual AWS workloads, with granular control         overriding higher-level assignments.<\/p>","href":"saas\/aws_workloads_protection_setup.html","attributes":{"data-id":"aws_workloads_protection_setup"},"menu":{"hasChildren":false},"tocID":"aws_workloads_protection_setup-d30753e14465","next":"aws_workloads_protection_setup-d30753e14465"},{"title":"Manage Amazon EC2 instances and EBS volumes","shortdesc":"<p class=\"shortdesc\">After you set up protection for Amazon EC2 instances and EBS volumes, <span class=\"ph\">RSC<\/span> takes automated snapshots of those instances and volumes based on the         configured policies in SLA Domains. You can also take on-demand snapshots, refresh AWS         accounts, and add AWS custom tags for better resource management.<\/p>","href":"saas\/aws_ec2_ebs_volume.html","attributes":{"data-id":"aws_ec2_ebs_volume"},"menu":{"hasChildren":false},"tocID":"aws_ec2_ebs_volume-d30753e14995","next":"aws_ec2_ebs_volume-d30753e14995"},{"title":"Manage Amazon RDS and Aurora databases","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects the data and resources of Amazon RDS and Amazon Aurora         databases.<\/p>","href":"saas\/aws_rds.html","attributes":{"data-id":"aws_rds"},"menu":{"hasChildren":false},"tocID":"aws_rds-d30753e15331","next":"aws_rds-d30753e15331"},{"title":"Manage Amazon S3","shortdesc":"<p class=\"shortdesc\">With <span class=\"ph\">RSC<\/span>, you can protect and recover your Amazon S3 buckets and         objects.<\/p>","href":"amazon_S3\/amazon_s3.html","attributes":{"data-id":"amazon_s3"},"menu":{"hasChildren":false},"tocID":"amazon_s3-d30753e15436","next":"amazon_s3-d30753e15436"},{"title":"Manage Amazon DynamoDB","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> secures Amazon DynamoDB tables with automated snapshots governed         by SLA Domain policies. You can gain insights from detailed snapshot data and optimize         resources using on-demand account refresh and AWS custom tags.<\/p>","href":"saas\/aws_dynamodb.html","attributes":{"data-id":"aws_dynamodb"},"menu":{"hasChildren":false},"tocID":"aws_dynamodb-d30753e15532","next":"aws_dynamodb-d30753e15532"},{"title":"Recover AWS workloads","shortdesc":"<p class=\"shortdesc\">After <span class=\"ph\">RSC<\/span> takes snapshots of your AWS workloads, you can recover the         required workloads.<\/p>","href":"saas\/aws_workload_recovery.html","attributes":{"data-id":"aws_workload_recovery"},"menu":{"hasChildren":false},"tocID":"aws_workload_recovery-d30753e15609","next":"aws_workload_recovery-d30753e15609"}]}};